// Summary statistics
export function getOpenClawStats() {
  const total = OPENCLAW_500.length;
  const implemented = OPENCLAW_500.filter(c => c.status === "implemented").length;
  const partial = OPENCLAW_500.filter(c => c.status === "partial").length;
  const stub = OPENCLAW_500.filter(c => c.status === "stub").length;
  const missing = OPENCLAW_500.filter(c => c.status === "missing").length;
  const byCategory = {} as Record<OpenClawCategory, { total: number; implemented: number; partial: number; stub: number; missing: number }>;
  for (const c of OPENCLAW_500) {
    if (!byCategory[c.category]) byCategory[c.category] = { total: 0, implemented: 0, partial: 0, stub: 0, missing: 0 };
    byCategory[c.category].total++;
    byCategory[c.category][c.status]++;
  }
  return { total, implemented, partial, stub, missing, byCategory };
}

export function getCapabilityById(id: number): OpenClawCapability | undefined {
  return OPENCLAW_500.find(c => c.id === id);
}

export function getCapabilitiesByCategory(category: OpenClawCategory): OpenClawCapability[] {
  return OPENCLAW_500.filter(c => c.category === category);
}

export function getGaps(): OpenClawCapability[] {
  return OPENCLAW_500.filter(c => c.status === "stub" || c.status === "missing");
}